glsl_code.green_glitch:
out vec4 fragColor;
uniform float uTear;
float hash(float x){ return fract(sin(x * 127.1) * 43758.5453); }
void main(){
  vec2 uv = vUV.st;
  float band = floor(uv.y * 34.0);
  float h = hash(band + floor(uv.x * 3.0));
  float tear = (h - 0.5) * 0.10 * max(uTear, 0.0) * step(0.55, h);
  vec4 src = texture(sTD2DInputs[0], uv + vec2(tear, 0.0));
  float energy = max(max(src.r, src.g), src.b);
  float scan = 0.75 + 0.25 * step(0.5, fract(uv.y * 96.0));
  vec3 green = vec3(0.02, 1.0, 0.22) * energy * scan;
  fragColor = TDOutputSwizzle(vec4(green, 1.0));
}

glsl_code.red_tracker:
out vec4 fragColor;
uniform float uThreshold;
uniform float uPointScale;
void main(){
  vec2 uv = vUV.st;
  vec4 src = texture(sTD2DInputs[0], uv);
  float l = dot(src.rgb, vec3(0.299, 0.587, 0.114));
  float lx = dot(texture(sTD2DInputs[0], uv + vec2(0.004, 0.0)).rgb, vec3(0.299, 0.587, 0.114));
  float ly = dot(texture(sTD2DInputs[0], uv + vec2(0.0, 0.004)).rgb, vec3(0.299, 0.587, 0.114));
  float edge = smoothstep(0.05, 0.22, abs(l - lx) + abs(l - ly));
  vec2 grid = fract(uv * vec2(18.0, 32.0));
  float dotMask = smoothstep(0.10 * max(uPointScale, 0.2), 0.0, length(grid - 0.5));
  float pointGate = step(max(uThreshold, 0.01), l) * dotMask;
  float tracker = clamp(edge * 0.85 + pointGate * 0.9, 0.0, 1.0);
  vec3 red = vec3(1.0, 0.03, 0.02) * tracker;
  fragColor = TDOutputSwizzle(vec4(red, tracker));
}
